import{_ as t,o as e,c as i,a2 as n}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F15: 關係人交易與利益輸送風險 - 財務分析專家審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/1727_中華化/20260430/F15_關係人交易與利益輸送風險_財務分析專家.md","filePath":"審計報告庫/財務審計/1727_中華化/20260430/F15_關係人交易與利益輸送風險_財務分析專家.md"}'),o={name:"審計報告庫/財務審計/1727_中華化/20260430/F15_關係人交易與利益輸送風險_財務分析專家.md"};function r(l,a,s,c,h,d){return e(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="f15-關係人交易與利益輸送風險-財務分析專家審計報告" tabindex="-1">F15: 關係人交易與利益輸送風險 - 財務分析專家審計報告 <a class="header-anchor" href="#f15-關係人交易與利益輸送風險-財務分析專家審計報告" aria-label="Permalink to &quot;F15: 關係人交易與利益輸送風險 - 財務分析專家審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>是否存在異常大額的關係人交易（連屬公司、子公司）？其定價是否符合市場行情？是否存在利益輸送或虛增利潤之嫌？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：關係人交易佔營收&lt;2%，定價透明、帳期合理，無利益輸送證據，治理風險<strong>低</strong>。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：截至 2025 Q4</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：H1 2024 關係人銷貨佔營收 1.84%（YoY -22%），期末 AR 淨額 $8,776K（佔總應收 1.86%），自高點回落。成本加成定價、帳期合理，無資金貸與或不動產交易。</li><li><strong>診斷見解</strong>：交易佔比遠低於 20% 門檻，餘額收斂，無利益輸送結構特徵及掏空紀錄。治理風險 <strong>S（優）</strong>。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="交易規模實測" tabindex="-1">交易規模實測 <a class="header-anchor" href="#交易規模實測" aria-label="Permalink to &quot;交易規模實測&quot;">​</a></h3><ul><li><strong>核心重點</strong>：H1 2024 關係人銷貨 $18,296K（佔營收 1.84%），全年化約 3.7%，遠低於 20% 門檻。世界永續交易自 H1 2023 之 $10,402K 驟降至 $293K，Q2 歸零，無擴大之虞。</li><li><strong>深度見解</strong>：交易集中於永光化學供應鏈整合，具產業鏈商業實質。</li></ul><h3 id="帳期異常偵測" tabindex="-1">帳期異常偵測 <a class="header-anchor" href="#帳期異常偵測" aria-label="Permalink to &quot;帳期異常偵測&quot;">​</a></h3><ul><li><strong>核心重點</strong>：關係人收款週轉約 134 天，略長於非關係人 86.6 天，然 AR 淨額已降至 $8,776K，帳齡壓力紓解。備抵損失 $109K（佔 AR 0.8%），風險可控。</li></ul><h3 id="定價公平性分析" tabindex="-1">定價公平性分析 <a class="header-anchor" href="#定價公平性分析" aria-label="Permalink to &quot;定價公平性分析&quot;">​</a></h3><ul><li><strong>核心重點</strong>：成本加成定價、收款期限與非關係人無異，未偵測價格異常。然「成本加成」機制缺乏獨立第三方背書，為唯一治理改善建議點。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：法人董事「永光化學」為最大關係人買方，其作為公司治理結構中之關鍵角色，若未來交易佔比突然攀升或帳期異常拉長，現有揭露機制之即時性與充分性仍有疑慮。建議投資人持續追蹤季度財報中關係人交易金額之季度變化率，若連續兩季佔營收突破 5%，應列為治理警訊。</li><li><strong>空頭風險二</strong>：世界永續科技（前總經理兼任董事）之交易雖已大幅縮減，然「前總經理」之職位異動時間點（113/1/16 辭職）與交易驟降高度吻合，暗示該交易可能具備「人情交易」而非純商業本質之特徵。若未來新任管理階層恢復與世界永續之大額往來，將需重新評估其商業合理性。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK — TaiwanStockFinancialStatements (balance_sheet)、TaiwanStockMonthRevenue 查詢 1727，2023-01-01 至 2026-04-30</li><li><strong>yfinance</strong>: N/A（結構化數據已由 FinMind 覆蓋）</li><li><strong>年報/法說</strong>: OK — 中華化 113 年 Q2 合併財務報告 PDF（chciworld.com.tw），附註七「關係人交易」章節</li><li><strong>網路搜尋</strong>: OK — 2024-2025 年無關係人掏空或訴訟之公開紀錄（cnyes.com、cmoney.tw、udn.com）</li><li><strong>關鍵核對碼</strong>: <code>AccountsReceivableDuefromRelatedPartiesNet 113/12/31 = 8,776,000</code>；<code>Revenue FY2024 = 500,519,000</code></li></ul><hr><p><strong>資料來源：</strong></p><ul><li>計算工具：FinMind 數據採集器（balance_sheet、finance）</li><li>原始數據：FinMind TaiwanStockFinancialStatements、TaiwanStockMonthRevenue</li><li>查詢參數：stock_id=1727, start=2023-01-01, end=2026-04-30</li><li>年報附註：中華化 113 年 Q2 合併財務報告 PDF「附註七、關係人交易」</li></ul>',22)])])}const g=t(o,[["render",r]]);export{u as __pageData,g as default};
